export type Item = { type: string };

export type QuoteInput = {
  items: Item[];
  customerYears: number;
  previousContracts: number;
};

export function quote(input: QuoteInput): number {
  const base = input.items.length === 0 ? 0 : 100;
  return base + 5;
}
